$(".color-radio input[name='color']").change(function () {
    let value = $(this).attr("data-value")
    let connectedInput = $(`.color-radio input[name='color2'][data-value="${value}"]`)

    $(connectedInput).prop("checked",true);
    $(connectedInput).trigger("change");
})

$(".color-radio input[name='color2']").change(function () {
    let value = $(this).attr("data-value")
    let connectedInput = $(`.color-radio input[name='color'][data-value="${value}"]`)

    if(connectedInput.length !== 0){
        $(connectedInput).prop("checked",true);
    }else{
        $(".color-radio input[name='color']").each(function () {
            $(this).prop("checked",false);
        })
    }

    $("._js-color-output").html(value)
})

$(".color-radio input[name='material']").change(function () {
    let value = $(this).attr("data-value")
    $("._js-material-output").html(value)
})

$(".series-item input[name='series']").change(function () {
    let value = $(this).attr("data-value")
    $("._js-series-output").html(value)
})

$(window).on('load resize', function(){
    if ($(window).width() <= 992) {
        $('.product-cart').insertAfter('.product-color');
        // $('.header-contacts').insertBefore('.header-search._movable-search');
        $('.header-catalog').insertAfter('.header-search._movable-search');
    } else{
        $('.product-cart').insertBefore('.about-marketplaces');
        // $('.header-contacts').insertAfter('.header-bottom__col');
        $('.header-catalog').insertAfter('.header-bottom__col');
    }
});

$("._toggle-reviews").click(function () {
    $(this).parents(".reviews-collection").toggleClass("_show-all")
})

$(".filter-group__top").click(function () {
    $(this).parents(".filter-group").toggleClass("_hide")
    $(this).siblings(".filter-group__bottom").slideToggle()
})

$(`[name="delivery-way"]`).change(function () {
    let value = $(this).attr("data-value")
    $(this)
        .parents(".order-form__group")
        .find(".order-form__variant")
        .removeClass("_active")

    $(`[data-val="${value}"]`).addClass("_active")
})

$('[name="deliveryType"]').change(function () {
    let id = $(this).attr("data-value")

    $(".order-delivery__content").removeClass("_active")
    $(`.order-delivery__content.${id}`).addClass("_active")
})

$(".sort-dropdown__show").click(function () {
    $(".sort-dropdown").toggleClass("_open")
})

$(document).mouseup( function(e){
    let div = $( ".sort-dropdown" );
    if ( !div.is(e.target)
        && div.has(e.target).length === 0 ) {
        if($(div).hasClass("_open")){
            $(div).removeClass("_open")
        }
    }
});

$(".sort-item input").change(function () {
    setCurrentSortType()
})

setCurrentSortType()

function setCurrentSortType(){
    let val = $(".sort-item input:checked").attr("data-value");
    $(".sort-dropdown ._current").html(val);
    $(".sort-dropdown").removeClass("_open")
}

$("._toggle-filter").click(function (){
    $("body").toggleClass("_filter-opened")
    $("body").toggleClass("fixed-body")
})
