$("._toggle-menu").click(function () {
    $(".header").toggleClass("_open")
    $("body").toggleClass("fixed-body")
})

$("._show-search-popup").focus(function () {
    openModal("searchModal")
})

$(".nav-item__top").click(function() {
    $(this).parents(".nav-item").toggleClass("_active")
    $(this).siblings(".nav-item__bottom").slideToggle()
})

$(".header-catalog__item").mouseover(function () {
    if(window.innerWidth<=992){
        return
    }

    let id = $(this).attr("data-id")

    $(".header-catalog__item").removeClass("_active")
    $(this).addClass("_active")

    $(".submenu").removeClass("_active")
    $(`.submenu[data-id="${id}"]`).addClass("_active")
})

$(".header-catalog__item").click(function () {
    let id = $(this).attr("data-id")

    $(".header-catalog__item").removeClass("_active")
    $(this).addClass("_active")

    $(".header").addClass("_open-sub-catalog")
    $(".submenu").removeClass("_active")
    $(`.submenu[data-id="${id}"]`).addClass("_active")
})

$(".header-top__back").click(function () {
    if($(".header").hasClass("_open-sub-catalog")){
        $(".header").removeClass("_open-sub-catalog")
    } else{
        $(".header").removeClass("_open-catalog")
    }
})

$("._toggle-catalog").click(function () {
    $(".header").toggleClass("_open-catalog")
    $("body").toggleClass("fixed-body")

    if(window.innerWidth<=992){
        $(".header").addClass("_open")
    }
})

$("._toggle-catalog2").click(function () {
    $(".header").toggleClass("_open-catalog")
})

$(".js-confirm-city").click(function () {
    $(".header-city").removeClass("_show-question")
})
$(".js-reject-city").click(function () {
    $(".header-city").removeClass("_show-question")
    $(".header").addClass("_show-city-select")
})
$(".city-popup__item input").change(function () {
    let val = $(this).attr("data-value")
    $(".js-city-output").html(val)
    $(".header").removeClass("_show-city-select")
})
$(".js-toggle-city-select").click(function () {
    $(".header-city").removeClass("_show-question")
    $(".header").toggleClass("_show-city-select")
    $(".header2").toggleClass("_show-city-select")
})

$(document).mouseup( function(e){
    let div = $( ".header, .header2" );
    if ( !div.is(e.target)
        && div.has(e.target).length === 0 ) {
        if($(div).hasClass("_show-city-select")){
            $(div).removeClass("_show-city-select")
        }
    }
});

